// Normalise le message entrant (texte ou interaction)
const msg = $input.first().json;
const changes = msg.entry?.[0]?.changes?.[0]?.value || {};
const waMsg = changes.messages?.[0] || {};
const from = waMsg.from;
let text = waMsg.text?.body || '';
const interactiveId = waMsg.interactive?.button_reply?.id || waMsg.interactive?.list_reply?.id || '';
const userMessage = text || interactiveId;
const sessionId = 'whatsapp_' + from;
const orderRef = 'CMD-' + from + '-' + Date.now();
return [{
  json: {
    chatId: from,
    userMessage,
    userName: 'Client',
    sessionId,
    orderRef,
    isCallback: !!interactiveId
  }
}];

// Analyse la commande utilisateur et route
const input = $input.first().json;
const msg = input.userMessage;
let routeTo = 'agent';
let vendorId = '', catId = '', prodId = '', price = '', productName = '';
let offset = 0;

if (msg.startsWith('VENDOR|')) { vendorId = msg.split('|')[1]; routeTo = 'categories'; }
else if (msg.startsWith('CAT|')) { const parts = msg.split('|'); catId = parts[1]; vendorId = parts[2]; routeTo = 'products'; }
else if (msg.startsWith('PROD|')) { const parts = msg.split('|'); prodId = parts[1]; catId = parts[2]; vendorId = parts[3]; price = parts[4]; routeTo = 'productDetail'; }
else if (msg.startsWith('PAGE|')) { const parts = msg.split('|'); catId = parts[1]; offset = parseInt(parts[2]); vendorId = parts[3]; routeTo = 'products'; }
else if (msg.startsWith('BACK_CAT|')) { const parts = msg.split('|'); catId = parts[1]; offset = parseInt(parts[2]); vendorId = parts[3]; routeTo = 'products'; }
else if (msg.startsWith('ADD_CART|')) { const parts = msg.split('|'); prodId = parts[1]; price = parts[2]; catId = parts[3]; vendorId = parts[4]; productName = parts.slice(5).join('|'); routeTo = 'addToCart'; }
else if (msg === 'VIEW_CART') routeTo = 'viewCart';
else if (msg.startsWith('REMOVE_CART|')) { prodId = msg.split('|')[1]; routeTo = 'removeFromCart'; }
else if (msg === 'ORDER_CART') routeTo = 'orderCart';
else if (msg.startsWith('ORDER|')) { const parts = msg.split('|'); prodId = parts[1]; price = parts[2]; catId = parts[3]; vendorId = parts[4]; productName = parts.slice(5).join('|'); routeTo = 'agent'; }
else if (msg === 'HOME' || msg === '/start') routeTo = 'vendors';

return [{ json: { ...input, routeTo, vendorId, catId, offset, prodId, price, productName } }];

// Construit la réponse pour les vendeurs (liste interactive)
const rows = $input.all().map(i => i.json).filter(v => v.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'text', text: 'Aucune boutique disponible.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
}
const sections = [{
  title: 'Boutiques',
  rows: rows.slice(0,10).map(v => ({ id: 'VENDOR|' + v.id, title: v.nom_boutique.substring(0,20), description: '' }))
}];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Choisissez une boutique :', sections, buttonText: 'Voir les boutiques' } }];

// Construit la réponse pour les catégories
const rows = $input.all().map(i => i.json).filter(c => c.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'text', text: 'Aucune catégorie.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
}
const sections = [{
  title: 'Catégories',
  rows: rows.slice(0,10).map(c => ({ id: 'CAT|' + c.id + '|' + nav.vendorId, title: c.nom.substring(0,20), description: '' }))
}];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Choisissez une catégorie :', sections, buttonText: 'Voir catégories' } }];

// Construit la réponse pour les produits
const rows = $input.all().map(i => i.json).filter(p => p.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'text', text: 'Aucun produit.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
}
const productRows = rows.slice(0,10).map(p => ({ id: 'PROD|' + p.id + '|' + nav.catId + '|' + nav.vendorId + '|' + p.prix, title: p.nom.substring(0,20) + ' — ' + p.prix + '$', description: '' }));
const sections = [{ title: 'Produits', rows: productRows }];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Produits :', sections, buttonText: 'Voir produits' } }];

// Détail produit : image + boutons (ou simple texte si pas d'image)
const BASE_URL = 'https://mhbeauty.shop/storage/';
const nav = $('Router navigation').first().json;
const p = $input.first().json;
if (!p || !p.id) {
  return [{ json: { chatId: nav.chatId, type: 'text', text: 'Produit introuvable.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
}
const rawUrl = (p.photo_url || '').trim();
const photoUrl = rawUrl ? (rawUrl.startsWith('http') ? rawUrl : BASE_URL + rawUrl.replace(/^\//, '')) : '';
const caption = `📦 *${p.nom}*\n\n${p.description || ''}\n\n💰 Prix : ${p.prix}$\n📏 Taille : ${p.taille || 'N/A'}`;
const addCart = `ADD_CART|${p.id}|${p.prix}|${nav.catId}|${nav.vendorId}|${p.nom}`;
const backCat = `BACK_CAT|${p.categorie_id}|0|${nav.vendorId}`;
const order = `ORDER|${p.id}|${p.prix}|${nav.catId}|${nav.vendorId}|${p.nom}`;
const buttons = [
  { id: addCart, title: '🛒 Ajouter au panier' },
  { id: backCat, title: '🔙 Continuer' },
  { id: order, title: '✅ Commander' }
];
if (photoUrl) {
  // Envoyer d'abord l'image, puis un message interactif (on renvoie deux objets ? Non, le nœud WhatsApp n'envoie qu'un seul message.
  // On va envoyer l'image seule avec légende, et les boutons dans un second message séparé ?
  // Pour simplifier, on préfère envoyer un message textuel avec boutons (pas d'image) pour que l'expérience soit fluide.
  // Vous pouvez améliorer en ajoutant un second nœud plus tard.
  return [{ json: { chatId: nav.chatId, type: 'image', image: { link: photoUrl, caption: caption } } }];
} else {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: caption, buttons: buttons } }];
}

// Gestion du panier (static data)
const input = $input.first().json;
const chatId = input.chatId;
const action = input.routeTo;
const sd = $getWorkflowStaticData('node');
if (!sd.paniers) sd.paniers = {};
if (!sd.paniers[chatId]) sd.paniers[chatId] = [];
let panier = sd.paniers[chatId];

if (action === 'addToCart') {
  const idx = panier.findIndex(i => i.prodId == input.prodId);
  if (idx >= 0) panier[idx].qty++;
  else panier.push({ prodId: input.prodId, nom: input.productName, prix: Number(input.price), vendorId: input.vendorId, catId: input.catId, qty: 1 });
  sd.paniers[chatId] = panier;
  return [{ json: { chatId, type: 'text', text: `✅ *${input.productName}* ajouté au panier !`, buttons: [
    { text: `🛍️ Voir panier (${panier.length})`, id: 'VIEW_CART' },
    { text: '🔙 Continuer', id: `BACK_CAT|${input.catId}|0|${input.vendorId}` },
    { text: '🏠 Accueil', id: 'HOME' }
  ] } }];
}
if (action === 'removeFromCart') {
  panier = panier.filter(i => i.prodId != input.prodId);
  sd.paniers[chatId] = panier;
  return [{ json: { chatId, type: 'text', text: '🗑️ Article retiré.', buttons: [
    { text: `🛍️ Voir panier (${panier.length})`, id: 'VIEW_CART' },
    { text: '🏠 Accueil', id: 'HOME' }
  ] } }];
}
if (action === 'orderCart') {
  if (!panier.length) return [{ json: { chatId, type: 'text', text: '🛒 Panier vide.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
  let total = 0, desc = '';
  const vendorId = panier[0].vendorId;
  panier.forEach(item => { const sous = item.prix * item.qty; total += sous; desc += `• ${item.nom} x${item.qty} = ${sous.toFixed(2)}$ `; });
  const safeProductName = `COMMANDE PANIER: ${desc.trim()} Total : ${total.toFixed(2)}$`;
  sd.paniers[chatId] = [];
  return [{ json: { ...input, routeTo: 'agent', vendorId, prodId: '', price: total.toFixed(2), productName: safeProductName } }];
}
// viewCart
if (!panier.length) return [{ json: { chatId, type: 'text', text: '🛒 Panier vide.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
let total = 0, textMsg = '🛒 *Votre panier :*\n\n';
const btns = [];
panier.forEach((item, idx) => {
  const sous = item.prix * item.qty;
  total += sous;
  textMsg += `${idx+1}. ${item.nom}\n   ${item.qty} × ${item.prix}$ = ${sous.toFixed(2)}$\n\n`;
  btns.push({ text: `🗑️ ${item.nom.substring(0,15)}`, id: `REMOVE_CART|${item.prodId}` });
});
textMsg += `──────────────\n💰 *Total : ${total.toFixed(2)}$*`;
btns.push({ text: '✅ Commander', id: 'ORDER_CART' }, { text: '🏠 Accueil', id: 'HOME' });
return [{ json: { chatId, type: 'text', text: textMsg, buttons: btns } }];

const response = $input.first().json.output || '';
const chatId = $('Router navigation').first().json.chatId;
const clean = response.replace(/\{[\s\S]*?\}/g, '').trim();
return [{ json: { chatId, type: 'text', text: clean || 'Je n\'ai pas compris.', buttons: [{ text: '🏠 Accueil', id: 'HOME' }] } }];
